export enum UserRole {
  FACULTY = 'FACULTY',
  STUDENT = 'STUDENT'
}

export enum Department {
  CS = 'Computer Science',
  ECE = 'Electronics',
  MECH = 'Mechanical',
  CIVIL = 'Civil'
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
}

export interface Faculty extends User {
  role: UserRole.FACULTY;
  username: string; // Used for login
}

export interface Student extends User {
  role: UserRole.STUDENT;
  department: Department;
  collegeClass: string; // "Class" is a reserved keyword
  regNo: string; // Login ID
  dob: string; // Password (DDMMYYYY)
  rollNo: string;
  college: string;
  performanceScore: number; // Mock score 0-100
  attendance: number; // Mock %
}

export interface Submission {
  id: string;
  studentId: string;
  title: string;
  type: 'Assignment' | 'Project' | 'Certificate';
  date: string;
  fileName: string;
}

export interface AIAnalysisResult {
  summary: string;
  strengths: string[];
  weaknesses: string[];
  recommendedPath: string;
}

// Gemini Types
export interface LiveConfig {
  voiceName?: string;
}

import { GoogleGenAI, Schema, Type } from "@google/genai";
import { Student, Submission, AIAnalysisResult } from "../types";

// Helper to get API Key safely
const getApiKey = (): string => {
  const key = process.env.API_KEY || localStorage.getItem("gemini_api_key") || "";
  if (!key) {
    console.warn("No API Key found. Features will fail.");
  }
  return key;
};

// --- Analytics Service ---

export const analyzeStudentData = async (
  student: Student,
  submissions: Submission[]
): Promise<AIAnalysisResult> => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API Key missing");

  const ai = new GoogleGenAI({ apiKey });

  const prompt = `
    Analyze the following student data for academic performance monitoring.
    Student: ${student.name}, Dept: ${student.department}, Score: ${student.performanceScore}%, Attendance: ${student.attendance}%.
    Submissions: ${submissions.map(s => `${s.type}: ${s.title}`).join(", ")}.

    Provide a JSON response with:
    1. A short summary paragraph.
    2. A list of 3 key strengths.
    3. A list of 3 areas for improvement (weaknesses).
    4. A recommended learning path sentence.
  `;

  // Define Schema
  const schema: Schema = {
    type: Type.OBJECT,
    properties: {
      summary: { type: Type.STRING },
      strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
      weaknesses: { type: Type.ARRAY, items: { type: Type.STRING } },
      recommendedPath: { type: Type.STRING },
    },
    required: ["summary", "strengths", "weaknesses", "recommendedPath"],
  };

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: schema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");
    return JSON.parse(text) as AIAnalysisResult;
  } catch (error) {
    console.error("AI Analysis Failed", error);
    throw error;
  }
};

// --- Live Audio Utilities ---

export const blobToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64data = reader.result as string;
      // remove data url part
      resolve(base64data.split(',')[1]);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

export function createPcmBlob(data: Float32Array): Blob {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return new Blob([int16.buffer], { type: 'audio/pcm' });
}

export function decodeAudio(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

