      else setError('Invalid Student credentials');
    }
  };

  const handleSignUp = (e: React.FormEvent) => {
    e.preventDefault();
    const req: PendingRequest = {
      id: `req${Date.now()}`,
      name: newName,
      role: role,
      password: role === UserRole.FACULTY ? password : newDob, // Use entered password for faculty, DOB for student
      username: role === UserRole.FACULTY ? id : undefined,
      regNo: role === UserRole.STUDENT ? newRegNo : undefined,
      dob: role === UserRole.STUDENT ? newDob : undefined,
      department: role === UserRole.STUDENT ? newDept : undefined,
      section: role === UserRole.STUDENT ? newSection : undefined,
      email: newEmail,
      collegeClass: 'I Year' // Default for sign up
    };
    onRequestSignup(req);
    setSuccessMsg("Request sent to Admin! Please wait for approval.");
    setIsSignUp(false); // Switch back to login
    setNewName(''); setId(''); setPassword(''); setNewRegNo(''); setNewDob('');
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-indigo-900 to-blue-800 flex items-center justify-center p-4">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden">
        <div className="bg-blue-600 p-6 text-center">
          <h1 className="text-2xl font-bold text-white">Mahendra Analytics</h1>
          <p className="text-blue-100 mt-1">Student Management Portal</p>
        </div>

        <div className="p-8">
          {/* Sign In / Sign Up Toggle */}
          <div className="flex justify-center mb-6 border-b">
             <button onClick={() => { setIsSignUp(false); setError(''); setSuccessMsg(''); }} className={`pb-2 px-4 font-bold ${!isSignUp ? 'text-blue-600 border-b-2 border-blue-600' : 'text-gray-400'}`}>Sign In</button>
             <button onClick={() => { setIsSignUp(true); setError(''); setSuccessMsg(''); }} className={`pb-2 px-4 font-bold ${isSignUp ? 'text-blue-600 border-b-2 border-blue-600' : 'text-gray-400'}`}>Sign Up</button>
          </div>

          {successMsg && <div className="mb-4 p-3 bg-green-100 text-green-700 text-sm rounded flex items-center gap-2"><CheckCircle size={16}/> {successMsg}</div>}
          {error && <div className="mb-4 p-3 bg-red-100 text-red-700 text-sm rounded flex items-center gap-2"><AlertCircle size={16}/> {error}</div>}

          {/* Role Selector */}
          <div className="flex bg-gray-100 rounded-lg p-1 mb-6">
            <button 
              className={`flex-1 py-2 text-sm font-medium rounded-md transition ${role === UserRole.FACULTY ? 'bg-white shadow text-blue-700' : 'text-gray-500'}`}
              onClick={() => setRole(UserRole.FACULTY)}
            >
              Faculty
            </button>
            <button 
              className={`flex-1 py-2 text-sm font-medium rounded-md transition ${role === UserRole.STUDENT ? 'bg-white shadow text-blue-700' : 'text-gray-500'}`}
              onClick={() => setRole(UserRole.STUDENT)}
            >
              Student
            </button>
          </div>

          {isSignUp ? (
             /* SIGN UP FORM */
             <form onSubmit={handleSignUp} className="space-y-4">
                <div>
                   <label className="text-xs font-bold text-gray-500">Full Name</label>
                   <input required type="text" className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500" value={newName} onChange={e => setNewName(e.target.value)} />
                </div>

                {role === UserRole.FACULTY ? (
                  <>
                    <div>
                       <label className="text-xs font-bold text-gray-500">Username</label>
                       <input required type="text" className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg px-3 py-2" value={id} onChange={e => setId(e.target.value)} />
                    </div>
                    <div>
                       <label className="text-xs font-bold text-gray-500">Password</label>
                       <input required type="password" className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg px-3 py-2" value={password} onChange={e => setPassword(e.target.value)} />
                    </div>
                  </>
                ) : (
                  <>
                    <div className="grid grid-cols-2 gap-2">
                      <div>
                        <label className="text-xs font-bold text-gray-500">Reg No</label>
                        <input required type="text" className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg px-3 py-2" value={newRegNo} onChange={e => setNewRegNo(e.target.value)} />
                      </div>
                      <div>
                        <label className="text-xs font-bold text-gray-500">DOB (DDMMYYYY)</label>
                        <input required type="text" className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg px-3 py-2" value={newDob} onChange={e => setNewDob(e.target.value)} />
                      </div>
                    </div>
                    <div className="grid grid-cols-2 gap-2">
                      <div>
                        <label className="text-xs font-bold text-gray-500">Department</label>
                        <select className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg px-3 py-2" value={newDept} onChange={e => setNewDept(e.target.value as Department)}>
                           {Object.values(Department).map(d => <option key={d} value={d}>{d}</option>)}
                        </select>
                      </div>
                      <div>
                        <label className="text-xs font-bold text-gray-500">Section</label>
                        <select className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg px-3 py-2" value={newSection} onChange={e => setNewSection(e.target.value as Section)}>
                           {Object.values(Section).map(s => <option key={s} value={s}>{s}</option>)}
                        </select>
                      </div>
                    </div>
                    <div>
                       <label className="text-xs font-bold text-gray-500">Email</label>
                       <input required type="email" className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg px-3 py-2" value={newEmail} onChange={e => setNewEmail(e.target.value)} />
                    </div>
                  </>
                )}

                <button type="submit" className="w-full bg-green-600 hover:bg-green-700 text-white font-bold py-3 rounded-lg transition shadow-lg mt-4">
                   Send Request
                </button>
             </form>
          ) : (
             /* SIGN IN FORM */
             <form onSubmit={handleLogin} className="space-y-4">
                <div>
                  <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">
                    {role === UserRole.FACULTY ? 'Username / ID' : 'Registration Number'}
                  </label>
                  <input 
                    type="text" 
                    required
                    className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg px-4 py-2 focus:ring-2 focus:ring-blue-500 outline-none transition"
                    value={id}
                    onChange={(e) => setId(e.target.value)}
                  />
                </div>
                <div>
                  <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">
                    {role === UserRole.FACULTY ? 'Password' : 'DOB (DDMMYYYY)'}
                  </label>
                  <input 
                    type="password" 
                    required
                    className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg px-4 py-2 focus:ring-2 focus:ring-blue-500 outline-none transition"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                  />
                </div>

                <button type="submit" className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-lg transition shadow-lg">
                  Login securely
                </button>
             </form>
          )}
        </div>
      </div>
    </div>
  );
};

// 3. Faculty Dashboard
const FacultyDashboard = ({ 
    user, students, submissions, facultyList, pendingRequests, setStudents, setFacultyList, setPendingRequests, messages 
  }: { 
    user: Faculty, students: Student[], submissions: Submission[], facultyList: any[], pendingRequests: PendingRequest[],
    setStudents: any, setFacultyList: any, setPendingRequests: any, messages: Message[] 
  }) => {

  const [view, setView] = useState<'home' | 'manage'>('home');
  const [selectedDept, setSelectedDept] = useState<Department | null>(null);
  const [selectedStudent, setSelectedStudent] = useState<Student | null>(null);
  const [aiAnalysis, setAiAnalysis] = useState<any>(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [showCallOverlay, setShowCallOverlay] = useState(false);

  // Forms
  const [newStudent, setNewStudent] = useState<Partial<Student>>({ role: UserRole.STUDENT, department: Department.CS, section: Section.A });
  const [newFaculty, setNewFaculty] = useState<{name: string, username: string, password: string}>({ name: '', username: '', password: '' });

  const runAnalysis = async (student: Student) => {
    setAnalyzing(true);
    try {
      const studentSubs = submissions.filter(s => s.studentId === student.id);
      const result = await analyzeStudentData(student, studentSubs);
      setAiAnalysis(result);
    } catch (err) {
      alert("Analysis failed. Check API Key.");
    } finally {
      setAnalyzing(false);
    }
  };

  const handleAddStudent = (e: React.FormEvent) => {
    e.preventDefault();
    if(newStudent.name && newStudent.regNo) {
      setStudents([...students, { ...newStudent, id: `s${Date.now()}`, performanceScore: 70, attendance: 100 } as Student]);
      setNewStudent({ role: UserRole.STUDENT, department: Department.CS, section: Section.A });
      alert("Student Added");
    }
  };

  const handleAddFaculty = (e: React.FormEvent) => {
    e.preventDefault();
    if(newFaculty.name && newFaculty.username) {
      setFacultyList([...facultyList, { ...newFaculty, id: `f${Date.now()}`, role: UserRole.FACULTY }]);
      setNewFaculty({ name: '', username: '', password: '' });
      alert("Faculty Added");
    }
  };

  const approveRequest = (req: PendingRequest) => {
    if (req.role === UserRole.STUDENT) {
        const student: Student = {
            id: `s${Date.now()}`,
            name: req.name,
            role: UserRole.STUDENT,
            department: req.department!,
            section: req.section || Section.A,
            collegeClass: req.collegeClass || 'I Year',
            regNo: req.regNo!,
            dob: req.dob || '00000000',
            rollNo: 'TEMP', // Admin can update later
            college: 'Mahendra Engineering College',
            email: req.email || '',
            phone: req.phone || '',
            performanceScore: 0,
            attendance: 0
        };
        setStudents([...students, student]);
    } else {
        const faculty = {
            id: `f${Date.now()}`,
            name: req.name,
            role: UserRole.FACULTY,
            username: req.username!,
            password: req.password!
        };
        setFacultyList([...facultyList, faculty]);
    }
    setPendingRequests(pendingRequests.filter(r => r.id !== req.id));
  };

  const rejectRequest = (id: string) => {
    if(confirm("Reject this sign up request?")) {
        setPendingRequests(pendingRequests.filter(r => r.id !== id));
    }
  };

  const removeStudent = (id: string) => {
    if(confirm("Are you sure?")) {
      setStudents(students.filter(s => s.id !== id));
      if(selectedStudent?.id === id) setSelectedStudent(null);
    }
  };

  const removeFaculty = (id: string) => {
    if(confirm("Remove this faculty member?")) {
      setFacultyList(facultyList.filter(f => f.id !== id));
    }
  };

  const initiateCall = () => {
    setShowCallOverlay(true);
    setTimeout(() => setShowCallOverlay(false), 3000); // Mock call duration
  };

  // --- RENDER HELPERS ---

  const renderHome = () => {
    if (selectedStudent) {
      // FULL STUDENT DETAIL VIEW
      return (
        <div className="animate-fade-in">
          <button onClick={() => setSelectedStudent(null)} className="mb-4 flex items-center gap-2 text-gray-600 hover:text-gray-900">
            <ArrowLeft size={20} /> Back to {selectedDept} Students
          </button>

          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            <div className="lg:col-span-2 space-y-6">
               {/* Header Card */}
               <div className="bg-white rounded-xl shadow-lg p-6 relative overflow-hidden">
                  <div className="absolute top-0 right-0 p-4 opacity-10"><Users size={120} /></div>
                  <div className="relative z-10 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                     <div>
                       <h2 className="text-3xl font-bold text-gray-800">{selectedStudent.name}</h2>
                       <p className="text-gray-500 text-lg">{selectedStudent.department} • Section {selectedStudent.section} • {selectedStudent.collegeClass}</p>
                     </div>
                     <div className="flex gap-3">
                       <button onClick={initiateCall} className="bg-green-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-green-700 shadow-md">
                         <Video size={18} /> Video Call
                       </button>
                       <button onClick={() => removeStudent(selectedStudent.id)} className="bg-red-100 text-red-600 px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-red-200">
                         <Trash2 size={18} /> Remove
                       </button>
                     </div>
                  </div>

                  <div className="mt-6 grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="flex items-center gap-3 text-gray-700 bg-gray-50 p-3 rounded">
                      <Mail size={18} className="text-indigo-500"/> {selectedStudent.email}
                    </div>
                    <div className="flex items-center gap-3 text-gray-700 bg-gray-50 p-3 rounded">
                      <Phone size={18} className="text-indigo-500"/> {selectedStudent.phone}
                    </div>
                    <div className="flex items-center gap-3 text-gray-700 bg-gray-50 p-3 rounded">
                      <span className="font-bold text-gray-500">Reg No:</span> {selectedStudent.regNo}
                    </div>
                    <div className="flex items-center gap-3 text-gray-700 bg-gray-50 p-3 rounded">
                      <span className="font-bold text-gray-500">DOB:</span> {selectedStudent.dob}
                    </div>
                  </div>
               </div>

               {/* Stats & AI */}
               <div className="bg-white rounded-xl shadow-lg p-6">
                  <div className="flex justify-between items-center mb-6">
                    <h3 className="text-xl font-bold">AI Performance Monitor</h3>
                    <button onClick={() => runAnalysis(selectedStudent)} disabled={analyzing} className="text-sm bg-indigo-100 text-indigo-700 px-3 py-1 rounded-full hover:bg-indigo-200">
                      {analyzing ? 'Analyzing...' : 'Refresh Analysis'}
                    </button>
                  </div>
                  <div className="grid grid-cols-2 gap-4 mb-6">
                     <div className="text-center p-4 bg-blue-50 rounded-xl">
                        <div className="text-3xl font-bold text-blue-600">{selectedStudent.performanceScore}%</div>
                        <div className="text-xs text-blue-400 uppercase font-bold">Academic Score</div>
                     </div>
                     <div className="text-center p-4 bg-green-50 rounded-xl">
                        <div className="text-3xl font-bold text-green-600">{selectedStudent.attendance}%</div>
                        <div className="text-xs text-green-400 uppercase font-bold">Attendance</div>
                     </div>
                  </div>
                  {aiAnalysis && (
                    <div className="space-y-4 bg-gray-50 p-4 rounded-lg">
                      <p className="text-sm text-gray-700 leading-relaxed"><span className="font-bold text-indigo-600">AI Summary:</span> {aiAnalysis.summary}</p>
                      <div className="grid grid-cols-2 gap-4 text-sm">
                        <div>
                          <p className="font-bold text-green-700 mb-1">Strengths</p>
                          <ul className="list-disc pl-4 text-gray-600">{aiAnalysis.strengths.map((s:string, i:number) => <li key={i}>{s}</li>)}</ul>
                        </div>
                        <div>
                          <p className="font-bold text-red-700 mb-1">Weaknesses</p>
                          <ul className="list-disc pl-4 text-gray-600">{aiAnalysis.weaknesses.map((s:string, i:number) => <li key={i}>{s}</li>)}</ul>
                        </div>
                      </div>
                    </div>
                  )}
               </div>
            </div>

            {/* Sidebar: Messages & Files */}
            <div className="space-y-6">
              <div className="bg-white rounded-xl shadow p-4">
                 <h3 className="font-bold text-gray-700 mb-3">Messages</h3>
                 <div className="h-40 overflow-y-auto space-y-2 border-t pt-2">
                    {messages.filter(m => m.fromId === selectedStudent.id || m.toId === selectedStudent.id).length === 0 && <p className="text-gray-400 text-xs">No messages yet.</p>}
                    {messages.filter(m => m.fromId === selectedStudent.id || m.toId === selectedStudent.id).map(m => (
                      <div key={m.id} className={`text-xs p-2 rounded ${m.fromId === user.id ? 'bg-indigo-100 ml-4' : 'bg-gray-100 mr-4'}`}>
                         <p className="font-bold">{m.senderName}</p>
                         <p>{m.content}</p>
                      </div>
                    ))}
                 </div>
              </div>

              <div className="bg-white rounded-xl shadow p-4">
                 <h3 className="font-bold text-gray-700 mb-3">Submissions</h3>
                 <div className="space-y-2">
                    {submissions.filter(s => s.studentId === selectedStudent.id).map(s => (
                      <div key={s.id} className="flex items-center justify-between p-2 bg-gray-50 rounded border">
                         <div className="truncate">
                           <p className="font-medium text-sm truncate">{s.title}</p>
                           <p className="text-xs text-gray-500">{s.type}</p>
                         </div>
                         <FileText size={16} className="text-gray-400"/>
                      </div>
                    ))}
                 </div>
              </div>
            </div>
          </div>
        </div>
      );
    }

    if (selectedDept) {
      // DEPARTMENT & SECTION VIEW
      const deptStudents = students.filter(s => s.department === selectedDept);

      return (
        <div className="animate-fade-in">
          <button onClick={() => setSelectedDept(null)} className="mb-4 flex items-center gap-2 text-gray-600 hover:text-gray-900">
            <ArrowLeft size={20} /> Back to Departments
          </button>
          <h2 className="text-2xl font-bold mb-6 text-indigo-900">{selectedDept} Students</h2>

          <div className="space-y-8">
            {Object.values(Section).map(section => {
               const sectionStudents = deptStudents.filter(s => s.section === section);
               return (
                  <div key={section} className="bg-white rounded-xl shadow-sm border p-4">
                     <h3 className="font-bold text-lg mb-4 text-indigo-800 border-b pb-2">Section {section}</h3>
                     <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                        {sectionStudents.map(s => (
                           <div key={s.id} onClick={() => setSelectedStudent(s)} className="p-4 rounded-lg bg-gray-50 hover:bg-indigo-50 border border-transparent hover:border-indigo-300 cursor-pointer transition flex items-center gap-3">
                              <div className="w-10 h-10 bg-indigo-200 rounded-full flex items-center justify-center font-bold text-indigo-700">{s.name.charAt(0)}</div>
                              <div>
                                 <p className="font-bold text-sm text-gray-800">{s.name}</p>
                                 <p className="text-xs text-gray-500">{s.regNo}</p>
                              </div>
                           </div>
                        ))}
                        {sectionStudents.length === 0 && <p className="text-sm text-gray-400 italic">No students in Section {section}</p>}
                     </div>
                  </div>
               )
            })}
          </div>
        </div>
      );
    }

    // DEPARTMENT CATEGORIES VIEW (DEFAULT)
    return (
      <div className="animate-fade-in">
         <h2 className="text-2xl font-bold mb-6 text-gray-800">Departments</h2>
         <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            {Object.values(Department).map(dept => (
              <div key={dept} onClick={() => setSelectedDept(dept)} className="bg-white rounded-xl shadow-md p-8 cursor-pointer hover:-translate-y-1 transition hover:shadow-xl border-t-4 border-indigo-500">
                 <h3 className="text-xl font-bold text-gray-800 mb-2">{dept}</h3>
                 <p className="text-gray-500 text-sm">{students.filter(s => s.department === dept).length} Students</p>
                 <div className="mt-4 flex justify-end">
                    <span className="text-indigo-600 text-sm font-medium">View Sections &rarr;</span>
                 </div>
              </div>
            ))}
         </div>
      </div>
    );
  };

  const renderManage = () => (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 animate-fade-in">

      {/* PENDING APPROVALS */}
      <div className="lg:col-span-2 bg-yellow-50 rounded-xl shadow p-6 border border-yellow-200">
         <h3 className="text-lg font-bold mb-4 flex items-center gap-2 text-yellow-800"><AlertCircle size={20}/> Pending Sign-Up Requests</h3>
         {pendingRequests.length === 0 && <p className="text-gray-500 text-sm">No pending requests.</p>}
         <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
             {pendingRequests.map(req => (
                 <div key={req.id} className="bg-white p-4 rounded-lg shadow-sm flex justify-between items-center">
                    <div>
                        <p className="font-bold text-gray-800">{req.name} <span className="text-xs bg-gray-200 px-2 rounded">{req.role}</span></p>
                        <p className="text-xs text-gray-500">{req.role === UserRole.STUDENT ? `${req.regNo} - ${req.department} (Sec ${req.section})` : req.username}</p>
                    </div>
                    <div className="flex gap-2">
                        <button onClick={() => approveRequest(req)} className="p-2 bg-green-100 text-green-600 rounded hover:bg-green-200"><Check size={18}/></button>
                        <button onClick={() => rejectRequest(req.id)} className="p-2 bg-red-100 text-red-600 rounded hover:bg-red-200"><X size={18}/></button>
                    </div>
                 </div>
             ))}
         </div>
      </div>

      {/* Manage Students */}
      <div className="bg-white rounded-xl shadow p-6">
         <h3 className="text-lg font-bold mb-4 flex items-center gap-2 text-indigo-900"><UserPlus size={20}/> Add Student</h3>
         <form onSubmit={handleAddStudent} className="space-y-4">
            <input required placeholder="Full Name" className="w-full bg-white text-gray-900 border border-gray-300 p-2 rounded" value={newStudent.name || ''} onChange={e => setNewStudent({...newStudent, name: e.target.value})} />
            <input required placeholder="Reg No (Login ID)" className="w-full bg-white text-gray-900 border border-gray-300 p-2 rounded" value={newStudent.regNo || ''} onChange={e => setNewStudent({...newStudent, regNo: e.target.value})} />
            <div className="grid grid-cols-2 gap-2">
               <input required placeholder="DOB (DDMMYYYY)" className="bg-white text-gray-900 border border-gray-300 p-2 rounded" value={newStudent.dob || ''} onChange={e => setNewStudent({...newStudent, dob: e.target.value})} />
               <input required placeholder="Class" className="bg-white text-gray-900 border border-gray-300 p-2 rounded" value={newStudent.collegeClass || ''} onChange={e => setNewStudent({...newStudent, collegeClass: e.target.value})} />
            </div>
            <div className="grid grid-cols-2 gap-2">
               <input placeholder="Email" className="bg-white text-gray-900 border border-gray-300 p-2 rounded" value={newStudent.email || ''} onChange={e => setNewStudent({...newStudent, email: e.target.value})} />
               <input placeholder="Phone" className="bg-white text-gray-900 border border-gray-300 p-2 rounded" value={newStudent.phone || ''} onChange={e => setNewStudent({...newStudent, phone: e.target.value})} />
            </div>
            <div className="grid grid-cols-2 gap-2">
                <select className="w-full bg-white text-gray-900 border border-gray-300 p-2 rounded" value={newStudent.department} onChange={e => setNewStudent({...newStudent, department: e.target.value as Department})}>
                    {Object.values(Department).map(d => <option key={d} value={d}>{d}</option>)}
                </select>
                <select className="w-full bg-white text-gray-900 border border-gray-300 p-2 rounded" value={newStudent.section} onChange={e => setNewStudent({...newStudent, section: e.target.value as Section})}>
                    {Object.values(Section).map(s => <option key={s} value={s}>Sec {s}</option>)}
                </select>
            </div>
            <button className="w-full bg-indigo-600 text-white font-bold rounded py-2 hover:bg-indigo-700">Add Student</button>
         </form>
      </div>

      {/* Manage Faculty */}
      <div className="bg-white rounded-xl shadow p-6">
         <h3 className="text-lg font-bold mb-4 flex items-center gap-2 text-indigo-900"><UserPlus size={20}/> Add Faculty</h3>
         <form onSubmit={handleAddFaculty} className="space-y-4">
            <input required placeholder="Faculty Name" className="w-full bg-white text-gray-900 border border-gray-300 p-2 rounded" value={newFaculty.name} onChange={e => setNewFaculty({...newFaculty, name: e.target.value})} />
            <input required placeholder="Username (Login ID)" className="w-full bg-white text-gray-900 border border-gray-300 p-2 rounded" value={newFaculty.username} onChange={e => setNewFaculty({...newFaculty, username: e.target.value})} />
            <input required placeholder="Password" type="password" className="w-full bg-white text-gray-900 border border-gray-300 p-2 rounded" value={newFaculty.password} onChange={e => setNewFaculty({...newFaculty, password: e.target.value})} />
            <button className="w-full bg-indigo-600 text-white font-bold rounded py-2 hover:bg-indigo-700">Create Admin</button>
         </form>

         <div className="mt-8">
            <h4 className="font-bold text-gray-700 mb-2">Existing Faculty</h4>
            <div className="space-y-2 max-h-40 overflow-y-auto">
               {facultyList.map(f => (
                 <div key={f.id} className="flex justify-between items-center p-2 bg-gray-50 rounded border">
                    <span className="text-sm font-medium">{f.name} ({f.username})</span>
                    {f.id !== user.id && (
                       <button onClick={() => removeFaculty(f.id)} className="text-red-500 hover:bg-red-50 p-1 rounded"><Trash2 size={16}/></button>
                    )}
                 </div>
               ))}
            </div>
         </div>
      </div>
    </div>
  );

  return (
    <div className="p-6 max-w-7xl mx-auto relative">
      <div className="flex justify-between items-center mb-8">
        <div>
          <h1 className="text-3xl font-bold text-gray-800">Faculty Admin</h1>
          <p className="text-gray-500">Welcome, {user.name}</p>
        </div>
        <div className="flex gap-2">
           <button onClick={() => { setView('home'); setSelectedDept(null); setSelectedStudent(null); }} className={`px-4 py-2 rounded-lg flex items-center gap-2 ${view === 'home' ? 'bg-indigo-600 text-white' : 'bg-white text-gray-700 border'}`}>
             <Users size={18} /> Home
           </button>
           <button onClick={() => setView('manage')} className={`px-4 py-2 rounded-lg flex items-center gap-2 ${view === 'manage' ? 'bg-indigo-600 text-white' : 'bg-white text-gray-700 border'}`}>
             <UserPlus size={18} /> Manage
           </button>
        </div>
      </div>

      {view === 'home' ? renderHome() : renderManage()}

      {/* Mock Video Call Overlay */}
      {showCallOverlay && (
        <div className="fixed inset-0 bg-black/90 z-50 flex flex-col items-center justify-center text-white">
           <div className="w-24 h-24 bg-gray-700 rounded-full flex items-center justify-center mb-6 animate-pulse">
              <Video size={48} />
           </div>
           <h2 className="text-2xl font-bold mb-2">Calling {selectedStudent?.name}...</h2>
           <p className="text-gray-400">Connecting secure video line</p>
           <button onClick={() => setShowCallOverlay(false)} className="mt-8 bg-red-600 px-8 py-3 rounded-full font-bold">End Call</button>
        </div>
      )}
    </div>
  );
};

// 4. Live Video Call (AI Tutor)
const LiveTutor = ({ onClose }: { onClose: () => void }) => {
  const [connected, setConnected] = useState(false);
  const [status, setStatus] = useState("Initializing...");
  const [volume, setVolume] = useState(0);

  useEffect(() => {
    let session: any = null;
    let audioContext: AudioContext | null = null;
    let stream: MediaStream | null = null;

    const startSession = async () => {
      const apiKey = process.env.API_KEY;
      if (!apiKey) { setStatus("API Key Missing"); return; }

      try {
        setStatus("Requesting permissions...");
        stream = await navigator.mediaDevices.getUserMedia({ audio: true });

        audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
        const outputNode = audioContext.createGain();
        outputNode.connect(audioContext.destination);

        const ai = new GoogleGenAI({ apiKey });
        setStatus("Connecting to Gemini Live...");

        const sessionPromise = ai.live.connect({
          model: 'gemini-2.5-flash-native-audio-preview-12-2025',
          config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } },
            systemInstruction: "You are a friendly and strict university professor conducting an oral exam (Viva Voce). Ask the student about their engineering subjects.",
          },
          callbacks: {
            onopen: () => {
              setConnected(true); setStatus("Connected (Listening)");
              const source = inputCtx.createMediaStreamSource(stream!);
              const processor = inputCtx.createScriptProcessor(4096, 1, 1);
              processor.onaudioprocess = (e) => {
                const inputData = e.inputBuffer.getChannelData(0);
                const pcmBlob = createPcmBlob(inputData);
                let sum = 0; for(let i=0; i<inputData.length; i++) sum += inputData[i] * inputData[i];
                setVolume(Math.sqrt(sum / inputData.length) * 100);
                sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
              };
              source.connect(processor); processor.connect(inputCtx.destination);
            },
            onmessage: async (msg: LiveServerMessage) => {
               const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
               if (audioData && audioContext) {
                 const buffer = await decodeAudioData(decodeAudio(audioData), audioContext);
                 const source = audioContext.createBufferSource();
                 source.buffer = buffer; source.connect(outputNode); source.start();
               }
            },
            onclose: () => { setConnected(false); setStatus("Session Closed"); },
            onerror: (e) => { console.error(e); setStatus("Connection Error"); }
          }
        });
        session = await sessionPromise;
      } catch (err) { setStatus("Failed: " + (err as Error).message); }
    };
    startSession();
    return () => { if (stream) stream.getTracks().forEach(track => track.stop()); if (audioContext) audioContext.close(); };
  }, []);

  return (
    <div className="fixed inset-0 bg-gray-900 z-50 flex flex-col">
      <div className="p-4 flex justify-between items-center bg-gray-800 text-white">
        <h2 className="font-bold text-lg flex items-center gap-2"><Video size={20}/> AI Oral Exam</h2>
        <button onClick={onClose} className="px-4 py-1 bg-red-600 rounded hover:bg-red-700">End</button>
      </div>
      <div className="flex-1 flex flex-col items-center justify-center p-8 relative overflow-hidden">
        <div className="absolute inset-0 flex items-center justify-center opacity-10">
            <div className={`w-96 h-96 rounded-full bg-blue-500 transition-all duration-75`} style={{ transform: `scale(${1 + volume/10})`}}></div>
        </div>
        <div className="z-10 bg-gray-800 p-8 rounded-2xl shadow-2xl text-center max-w-md w-full border border-gray-700">
           <div className={`w-24 h-24 mx-auto rounded-full mb-6 flex items-center justify-center ${connected ? 'bg-green-500 animate-pulse' : 'bg-gray-600'}`}>
              <Video size={40} className="text-white" />
           </div>
           <h3 className="text-2xl font-bold text-white mb-2">{connected ? "Exam in Progress" : "Connecting..."}</h3>
           <p className="text-gray-400 mb-8">{status}</p>
        </div>
      </div>
    </div>
  );
};

// 5. Student Dashboard
const StudentDashboard = ({ 
    user, submissions, facultyList, onUpload, onSendMessage 
  }: { 
    user: Student, submissions: Submission[], facultyList: Faculty[], onUpload: (sub: Submission) => void, onSendMessage: (toId: string, content: string) => void 
  }) => {
  const [showLiveCall, setShowLiveCall] = useState(false);

  // FAB State
  const [showFabMenu, setShowFabMenu] = useState(false);
  const [showUploadModal, setShowUploadModal] = useState(false);
  const [showMessageModal, setShowMessageModal] = useState(false);

  // Form State
  const [uploadTitle, setUploadTitle] = useState('');
  const [uploadType, setUploadType] = useState<Submission['type']>('Assignment');
  const [msgContent, setMsgContent] = useState('');
  const [msgRecipient, setMsgRecipient] = useState(facultyList[0]?.id || '');

  const handleUpload = (e: React.FormEvent) => {
    e.preventDefault();
    onUpload({
      id: `sub${Date.now()}`, studentId: user.id, title: uploadTitle, type: uploadType,
      date: new Date().toISOString().split('T')[0], fileName: 'uploaded_file.pdf'
    });
    setUploadTitle(''); setShowUploadModal(false);
    alert("Uploaded Successfully!");
  };

  const handleSendMsg = (e: React.FormEvent) => {
    e.preventDefault();
    if(msgRecipient && msgContent) {
      onSendMessage(msgRecipient, msgContent);
      setMsgContent(''); setShowMessageModal(false);
      alert("Message Sent!");
    }
  };

  const mySubmissions = submissions.filter(s => s.studentId === user.id);
  const data = [
    { name: 'Assignments', value: mySubmissions.filter(s => s.type === 'Assignment').length },
    { name: 'Projects', value: mySubmissions.filter(s => s.type === 'Project').length },
    { name: 'Certificates', value: mySubmissions.filter(s => s.type === 'Certificate').length },
  ];
  const COLORS = ['#0088FE', '#00C49F', '#FFBB28'];

  if (showLiveCall) return <LiveTutor onClose={() => setShowLiveCall(false)} />;

  return (
    <div className="p-6 max-w-7xl mx-auto pb-24">
       <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
        <div>
          <h1 className="text-3xl font-bold text-gray-800">Student Portal</h1>
          <p className="text-gray-500">Reg No: {user.regNo} | Dept: {user.department} (Sec {user.section})</p>
        </div>
        <button onClick={() => setShowLiveCall(true)} className="bg-red-600 text-white px-6 py-3 rounded-lg font-bold shadow-lg hover:bg-red-700 transition flex items-center gap-2 animate-pulse">
          <Video size={20} /> Join Live Oral Exam
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Profile Card */}
        <div className="bg-white rounded-xl shadow p-6">
          <div className="flex flex-col items-center pb-6 border-b">
            <div className="w-20 h-20 bg-blue-100 rounded-full flex items-center justify-center text-blue-600 font-bold text-2xl mb-4">{user.name.charAt(0)}</div>
            <h2 className="text-xl font-bold">{user.name}</h2>
            <p className="text-gray-500">{user.department} - {user.collegeClass}</p>
          </div>
          <div className="mt-6 space-y-4">
             <div className="p-3 bg-gray-50 rounded text-sm text-gray-600 flex gap-2"><Mail size={16}/> {user.email}</div>
             <div className="p-3 bg-gray-50 rounded text-sm text-gray-600 flex gap-2"><Phone size={16}/> {user.phone}</div>
             <div className="flex justify-between border-t pt-4"><span className="text-gray-600">Attendance</span><span className="font-bold text-green-600">{user.attendance}%</span></div>
             <div className="flex justify-between"><span className="text-gray-600">Perf. Score</span><span className="font-bold text-blue-600">{user.performanceScore}/100</span></div>
          </div>
        </div>

        {/* Dashboard Content */}
        <div className="lg:col-span-2 space-y-6">
            <div className="bg-white rounded-xl shadow p-6">
              <h3 className="font-bold text-lg mb-4 flex items-center gap-2"><FileText size={18}/> Submission History</h3>
              <div className="flex flex-col md:flex-row">
                 <div className="flex-1 space-y-3 max-h-60 overflow-y-auto pr-2">
                    {mySubmissions.length === 0 && <p className="text-gray-400 text-sm">No submissions yet. Use the + button.</p>}
                    {mySubmissions.map(s => (
                      <div key={s.id} className="flex justify-between items-center p-3 bg-gray-50 rounded border border-gray-100">
                         <div><p className="font-medium text-gray-800">{s.title}</p><p className="text-xs text-gray-500">{s.type} • {s.date}</p></div>
                         <span className="text-xs bg-green-100 text-green-800 px-2 py-1 rounded">Submitted</span>
                      </div>
                    ))}
                 </div>
                 <div className="w-full md:w-48 h-48">
                    <ResponsiveContainer width="100%" height="100%">
                      <PieChart>
                        <Pie data={data} innerRadius={40} outerRadius={60} paddingAngle={5} dataKey="value">
                          {data.map((entry, index) => <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />)}
                        </Pie>
                        <Tooltip />
                      </PieChart>
                    </ResponsiveContainer>
                    <p className="text-center text-xs text-gray-400">Activity</p>
                 </div>
              </div>
            </div>
        </div>
      </div>

      {/* FAB (Floating Action Button) */}
      <div className="fixed bottom-8 right-8 flex flex-col items-end z-40">
        {showFabMenu && (
          <div className="mb-4 space-y-2 flex flex-col items-end animate-fade-in-up">
             <button onClick={() => { setShowMessageModal(true); setShowFabMenu(false); }} className="flex items-center gap-2 bg-white text-gray-700 px-4 py-2 rounded-lg shadow-lg hover:bg-gray-50">
                Message Faculty <MessageSquare size={18} className="text-blue-500"/>
             </button>
             <button onClick={() => { setShowUploadModal(true); setShowFabMenu(false); }} className="flex items-center gap-2 bg-white text-gray-700 px-4 py-2 rounded-lg shadow-lg hover:bg-gray-50">
                Upload Project/Cert <Upload size={18} className="text-green-500"/>
             </button>
          </div>
        )}
        <button onClick={() => setShowFabMenu(!showFabMenu)} className={`w-14 h-14 rounded-full shadow-xl flex items-center justify-center text-white transition-transform ${showFabMenu ? 'bg-gray-700 rotate-45' : 'bg-indigo-600 hover:bg-indigo-700'}`}>
          <Plus size={28} />
        </button>
      </div>

      {/* Upload Modal */}
      {showUploadModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
           <div className="bg-white rounded-xl p-6 w-full max-w-md">
              <div className="flex justify-between mb-4"><h3 className="font-bold text-lg">Upload File</h3><button onClick={() => setShowUploadModal(false)}><X/></button></div>
              <form onSubmit={handleUpload} className="space-y-4">
                 <input required className="w-full bg-white text-gray-900 border border-gray-300 p-2 rounded" placeholder="Title" value={uploadTitle} onChange={e => setUploadTitle(e.target.value)}/>
                 <select className="w-full bg-white text-gray-900 border border-gray-300 p-2 rounded" value={uploadType} onChange={e => setUploadType(e.target.value as any)}>
                    <option value="Assignment">Assignment</option><option value="Project">Project</option><option value="Certificate">Certificate</option>
                 </select>
                 <input type="file" className="w-full text-sm"/>
                 <button className="w-full bg-indigo-600 text-white py-2 rounded font-bold">Submit</button>
              </form>
           </div>
        </div>
      )}

      {/* Message Modal */}
      {showMessageModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
           <div className="bg-white rounded-xl p-6 w-full max-w-md">
              <div className="flex justify-between mb-4"><h3 className="font-bold text-lg">Send Message</h3><button onClick={() => setShowMessageModal(false)}><X/></button></div>
              <form onSubmit={handleSendMsg} className="space-y-4">
                 <label className="text-sm font-bold text-gray-500">To Faculty</label>
                 <select className="w-full bg-white text-gray-900 border border-gray-300 p-2 rounded" value={msgRecipient} onChange={e => setMsgRecipient(e.target.value)}>
                    {facultyList.map(f => <option key={f.id} value={f.id}>{f.name}</option>)}
                 </select>
                 <textarea required className="w-full bg-white text-gray-900 border border-gray-300 p-2 rounded h-24" placeholder="Your message..." value={msgContent} onChange={e => setMsgContent(e.target.value)}/>
                 <button className="w-full bg-blue-600 text-white py-2 rounded font-bold">Send</button>
              </form>
           </div>
        </div>
      )}
    </div>
  );
};


// 6. Main App Shell
export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [students, setStudents] = useState<Student[]>(MOCK_STUDENTS);
  const [facultyList, setFacultyList] = useState<any[]>(MOCK_FACULTY);
  const [pendingRequests, setPendingRequests] = useState<PendingRequest[]>([]);
  const [submissions, setSubmissions] = useState<Submission[]>(MOCK_SUBMISSIONS);
  const [messages, setMessages] = useState<Message[]>([]);

  const handleSendMessage = (toId: string, content: string) => {
    if(!user) return;
    const msg: Message = {
      id: `m${Date.now()}`, fromId: user.id, toId, content, timestamp: new Date().toISOString(), senderName: user.name
    };
    setMessages([...messages, msg]);
  };

  const handleLogout = () => setUser(null);

  if (!user) return <Login onLogin={setUser} facultyList={facultyList} onRequestSignup={(req) => setPendingRequests([...pendingRequests, req])} />;

  return (
    <div className="min-h-screen bg-gray-50 text-gray-900 font-sans">
      <nav className="bg-white border-b sticky top-0 z-40 shadow-sm">
        <div className="max-w-7xl mx-auto px-6 py-4 flex justify-between items-center">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold text-lg">M</div>
            <span className="font-bold text-xl tracking-tight text-indigo-900">Mahendra Analytics</span>
          </div>
          <button onClick={handleLogout} className="flex items-center gap-2 text-sm font-medium text-gray-500 hover:text-red-600 transition">
            <LogOut size={16} /> Logout
          </button>
        </div>
      </nav>

      <main>
        {user.role === UserRole.FACULTY ? (
          <FacultyDashboard 
            user={user as Faculty} 
            students={students} 
            submissions={submissions}
            facultyList={facultyList}
            pendingRequests={pendingRequests}
            messages={messages}
            setStudents={setStudents}
            setFacultyList={setFacultyList}
            setPendingRequests={setPendingRequests}
          />
        ) : (
          <StudentDashboard 
            user={user as Student} 
            submissions={submissions}
            facultyList={facultyList}
            onUpload={(sub) => setSubmissions([...submissions, sub])}
            onSendMessage={handleSendMessage}
          />
        )}
      </main>
    </div>
  );
}

