};


// 6. Main App Shell
export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [students, setStudents] = useState<Student[]>(MOCK_STUDENTS);
  const [facultyList, setFacultyList] = useState<any[]>(MOCK_FACULTY);
  const [pendingRequests, setPendingRequests] = useState<PendingRequest[]>([]);
  const [submissions, setSubmissions] = useState<Submission[]>(MOCK_SUBMISSIONS);
  const [messages, setMessages] = useState<Message[]>([]);

  const handleSendMessage = (toId: string, content: string) => {
    if(!user) return;
    const msg: Message = {
      id: `m${Date.now()}`, fromId: user.id, toId, content, timestamp: new Date().toISOString(), senderName: user.name
    };
    setMessages([...messages, msg]);
  };

  const handleLogout = () => setUser(null);

  if (!user) return <Login onLogin={setUser} facultyList={facultyList} studentList={students} onRequestSignup={(req) => setPendingRequests([...pendingRequests, req])} />;

  return (
    <div className="min-h-screen bg-gray-50 text-gray-900 font-sans">
      <nav className="bg-white border-b sticky top-0 z-40 shadow-sm">
        <div className="max-w-7xl mx-auto px-6 py-4 flex justify-between items-center">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold text-lg">M</div>
            <span className="font-bold text-xl tracking-tight text-indigo-900">Mahendra Analytics</span>
          </div>
          <button onClick={handleLogout} className="flex items-center gap-2 text-sm font-medium text-gray-500 hover:text-red-600 transition">
            <LogOut size={16} /> Logout
          </button>
        </div>
      </nav>

      <main>
        {user.role === UserRole.FACULTY ? (
          <FacultyDashboard 
            user={user as Faculty} 
            students={students} 
            submissions={submissions}
            facultyList={facultyList}
            pendingRequests={pendingRequests}
            messages={messages}
            setStudents={setStudents}
            setFacultyList={setFacultyList}
            setPendingRequests={setPendingRequests}
          />
        ) : (
          <StudentDashboard 
            user={user as Student} 
            submissions={submissions}
            facultyList={facultyList}
            onUpload={(sub) => setSubmissions([...submissions, sub])}
            onSendMessage={handleSendMessage}
          />
        )}
      </main>
    </div>
  );
}

export enum UserRole {
  FACULTY = 'FACULTY',
  STUDENT = 'STUDENT'
}

export enum Department {
  CSE = 'CSE',
  AIML = 'AI & ML',
  IT = 'Information Technology',
  ECE = 'Electronics & Comm',
  EEE = 'Electrical & Electronics',
  MECH = 'Mechanical',
  CIVIL = 'Civil'
}

export enum Section {
  A = 'A',
  B = 'B',
  C = 'C',
  D = 'D'
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
}

export interface Faculty extends User {
  role: UserRole.FACULTY;
  username: string; // Used for login
}

export interface Student extends User {
  role: UserRole.STUDENT;
  department: Department;
  section: Section; 
  collegeClass: string; // e.g. "IV Year"
  regNo: string; // Login ID
  dob: string; // Password (DDMMYYYY)
  rollNo: string;
  college: string;
  email: string;
  phone: string;
  performanceScore: number; // Mock score 0-100
  attendance: number; // Mock %
}

export interface PendingRequest {
  id: string;
  name: string;
  role: UserRole;
  // Common fields
  username?: string; // For faculty
  regNo?: string;    // For student
  password?: string; // Stored temporarily until approval
  // Student specific
  department?: Department;
  section?: Section;
  collegeClass?: string;
  dob?: string;
  email?: string;
  phone?: string;
}

export interface Submission {
  id: string;
  studentId: string;
  title: string;
  type: 'Assignment' | 'Project' | 'Certificate' | 'Link';
  date: string;
  fileName?: string;
  link?: string;
  description?: string;
}

export interface Message {
  id: string;
  fromId: string;
  toId: string;
  content: string;
  timestamp: string;
  senderName: string;
}

export interface AIAnalysisResult {
  summary: string;
  strengths: string[];
  weaknesses: string[];
  recommendedPath: string;
}

// Gemini Types
export interface LiveConfig {
  voiceName?: string;
}

